type FieldDef = {
  name: string; label: string; type?: 'number' | 'text' | 'select'
  min?: number; max?: number; step?: number | string; placeholder?: string; unit?: string
  options?: { label: string; value: string }[]
}

type ResultValue = { result: number | string; label: string; unit: string; steps?: (string | { label: string; value: string })[] }

type CalcDef = {
  schema: z.ZodObject<any, any, any>
  fields: FieldDef[]
  compute: (values: Record<string, unknown>) => ResultValue
  description: string
  formula: string
  interpretation: string
  presets?: { label: string; values: Record<string, string> }[]
}

function n(v: unknown): number {
  if (typeof v === 'number') return v
  const x = parseFloat(String(v ?? ''))
  return isNaN(x) ? 0 : x
}

