// --- Linear conversion helper ---
function linearConvert(v: number, from: string, to: string, factors: Record<string, number>): number {
  return v * (factors[from] ?? 1) / (factors[to] ?? 1)
}

// --- Temperature conversion helper (not linear) ---
function convertTemp(v: number, from: string, to: string): number {
  let c: number
  if (from === '°C') c = v
  else if (from === '°F') c = (v - 32) * 5 / 9
  else c = v - 273.15
  if (to === '°C') return c
  if (to === '°F') return c * 9 / 5 + 32
  return c + 273.15
}

