// Try to resolve a unit alias to a valid option value
function resolveUnit(name: string): string | null {
  const key = name.toLowerCase().replace(/[-\s]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '')
  // Try exact match
  if (unitAliases[key]) return unitAliases[key]
  // Try without hyphens
  if (unitAliases[key.replace(/-/g, '')]) return unitAliases[key.replace(/-/g, '')]
  // Try as-is
  if (unitAliases[name]) return unitAliases[name]
  if (unitAliases[name.toLowerCase()]) return unitAliases[name.toLowerCase()]
  return null
}

function slugToDimension(fromUnit: string, toUnit: string): string | null {
  // Check temperature first (special handling)
  const tempUnits = ['°C', '°F', 'K', 'celsius', 'fahrenheit', 'kelvin']
  const fLower = fromUnit.toLowerCase()
  const tLower = toUnit.toLowerCase()
  if (tempUnits.some(u => fLower.includes(u) || tLower.includes(u))) return 'temperature'
  
  // Check each dimension's factor map for matching units
  for (const [dim, info] of Object.entries(dimMaps)) {
    if (dim === 'temperature') continue
    const factors = info.factors
    const fromResolved = resolveUnit(fromUnit)
    const toResolved = resolveUnit(toUnit)
    if (fromResolved && factors[fromResolved] !== undefined) return dim
    if (toResolved && factors[toResolved] !== undefined) return dim
  }
  return null
}

function buildConversionDef(fromUnitSlug: string, toUnitSlug: string, slug: string): CalcDef | null {
  const fromResolved = resolveUnit(fromUnitSlug)
  const toResolved = resolveUnit(toUnitSlug)
  if (!fromResolved || !toResolved) return null
  
  const dim = slugToDimension(fromUnitSlug, toUnitSlug)
  if (!dim) return null
  
  // Build display labels from slug parts
  const fromLabel = fromUnitSlug.replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase())
  const toLabel = toUnitSlug.replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase())
  
  if (dim === 'temperature') {
    return {
      schema: z.object({ value: z.string().min(1).refine(v => !isNaN(parseFloat(v)), 'Must be a number') }),
      fields: [{ name: 'value', label: fromLabel, step: '0.1', min: -459 }],
      compute: (v) => {
        const val = n(v.value)
        const r = convertTemp(val, fromResolved, toResolved)
        return { result: r, label: 'Temperature', unit: toResolved, steps: [`${val}${fromResolved} = ${r.toFixed(2)}${toResolved}`] }
      },
      description: `Convert ${fromLabel} to ${toLabel}.`,
      formula: `Formula for ${fromLabel} → ${toLabel}`,
      interpretation: `${fromLabel} converted to ${toLabel}.`,
    }
  }
  
  const factors = dimMaps[dim]?.factors
  if (!factors || factors[fromResolved] === undefined || factors[toResolved] === undefined) return null
  
  return {
    schema: z.object({ value: z.string().min(1).refine(v => !isNaN(parseFloat(v)), 'Must be a number') }),
    fields: [{ name: 'value', label: fromLabel, step: '0.001', min: 0 }],
    compute: (v) => {
      const val = n(v.value)
      const r = linearConvert(val, fromResolved, toResolved, factors)
      return { result: r, label: dimMaps[dim]?.name || 'Value', unit: toResolved, steps: [`${val} ${fromResolved} = ${r.toFixed(4)} ${toResolved}`] }
    },
    description: `Convert ${fromLabel} to ${toLabel}.`,
    formula: `Formula for ${fromLabel} → ${toLabel}`,
    interpretation: `1 ${fromResolved} = ${linearConvert(1, fromResolved, toResolved, factors).toFixed(6)} ${toResolved}.`,
  }
}

function parseSlug(slug: string): { from: string; to: string } | null {
  // Pattern: "X-to-Y"
  const match = slug.match(/^(.+)-to-(.+)$/)
  if (match) return { from: match[1], to: match[2] }
  // Pattern: "X-Y" where both parts resolve to known units (using last hyphen)
  const idx = slug.lastIndexOf('-')
  if (idx > 0) {
    const from = slug.slice(0, idx)
    const to = slug.slice(idx + 1)
    if (resolveUnit(from) && resolveUnit(to)) return { from, to }
  }
  return null
}

function buildDynamicDef(slug: string): CalcDef | null {
  const parsed = parseSlug(slug)
  if (!parsed) return null
  return buildConversionDef(parsed.from, parsed.to, slug)
}

interface Props {
  calculator: { slug: string; title: string; description: string; tier: string; category: string; hubSlug: string; hubName: string; keywords: string[]; dataDependent?: boolean; dataRefreshCadence?: string }
}

export function GenericConversionCalculator({ calculator }: Props) {
  const calcDef = calcDefs[calculator.slug] || buildDynamicDef(calculator.slug) || calcDefs['inches-to-cm']
  const [useSlider, setUseSlider] = useState(true)
  const [lockedFields, setLockedFields] = useState<Set<string>>(new Set())
  const [extraFields, setExtraFields] = useState<Record<string, string>>({})
  const toggleLock = useCallback((name: string) => {
    setLockedFields(prev => { const next = new Set(prev); if (next.has(name)) next.delete(name); else next.add(name); return next })
  }, [])

  const form = useForm({ resolver: zodResolver(calcDef.schema), mode: 'onChange' })
  const watched = useWatch({ control: form.control })
  const v = watched as Record<string, unknown>
  const watchedInputs = useMemo(() => {
    const vals = (typeof watched === 'object' && watched !== null) ? watched as Record<string, string> : {}
    return Object.fromEntries(Object.entries(vals).filter(([, v]) => v !== undefined && v !== ''))
  }, [watched])

  const result = useMemo(() => {
    if (!v || Object.keys(v).length === 0) return null
    const res = calcDef.compute(v)
    const displayVal = typeof res.result === 'number' ? res.result.toFixed(4) : res.result
    const numVal = typeof res.result === 'number' ? res.result : undefined
    const hasUnits = calcDef.fields.some(f => f.name === 'fromUnit')

    let reverseRes = null
    if (hasUnits && numVal !== undefined && v.fromUnit && v.toUnit) {
      try {
        reverseRes = calcDef.compute({ ...v, fromUnit: v.toUnit, toUnit: v.fromUnit })
      } catch {}
    }

    return (
      <div className="space-y-4">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          <div className="text-center bg-gray-50 dark:bg-gray-900 rounded-xl p-4">
            <p className="text-xs text-gray-500 dark:text-gray-400">{res.label}</p>
            <p className="text-3xl font-bold text-[#06b6d4]">{displayVal} {res.unit}</p>
          </div>
          {reverseRes && (
            <div className="text-center bg-gray-50 dark:bg-gray-900 rounded-xl p-4 ring-1 ring-[#06b6d4]/20">
              <p className="text-xs text-gray-500 dark:text-gray-400">{reverseRes.label}</p>
              <p className="text-3xl font-bold text-[#06b6d4]">{typeof reverseRes.result === 'number' ? reverseRes.result.toFixed(4) : reverseRes.result} {reverseRes.unit}</p>
            </div>
          )}
        </div>
        {numVal !== undefined && hasUnits && (
          <div className="text-center">
            <button onClick={() => {
  if (lockedFields.has('value')) return
  const curFrom = String(v.fromUnit || '')
  const curTo = String(v.toUnit || '')
  if (curFrom && curTo) {
    form.setValue('fromUnit' as any, curTo)
    form.setValue('toUnit' as any, curFrom)
    form.setValue('value', String(numVal))
  } else {
    form.setValue('value', String(numVal))
  }
}} className="inline-flex items-center gap-1 text-xs text-gray-400 hover:text-[#06b6d4] transition-colors">
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16V4m0 0L3 8m4-4l4 4m6 0v12m0 0l4-4m-4 4l-4-4" /></svg>
              Swap
            </button>
          </div>
        )}
        {res.steps && res.steps.length > 0 && (
          <div className="border-t border-gray-200 dark:border-gray-700 pt-3 text-xs text-gray-500 space-y-1.5">
            <p className="font-medium text-gray-700 dark:text-gray-300">Steps</p>
            {res.steps.map((step, i) => (
              <div key={i} className="flex items-start gap-2">
                <span className="flex-shrink-0 w-4 h-4 rounded-full bg-[#1a3a8a]/10 text-[#06b6d4] flex items-center justify-center text-[10px] font-medium mt-0.5">{i + 1}</span>
                <span>{typeof step === 'string' ? step : `${step.label}: ${step.value}`}</span>
              </div>
            ))}
          </div>
        )}
      </div>
    )
  }, [v, calcDef, form])

  const copyResultText = useMemo(() => {
    const lines: string[] = [calculator.title]
    Object.entries(v).filter(([, val]) => val).forEach(([k, val]) => lines.push(`${k}: ${val}`))
    return lines.join('\n')
  }, [calculator.title, v])

  const presets = calcDef?.presets || []
  const applyPreset = useCallback((preset: { label: string; values: Record<string, string> }) => {
    Object.entries(preset.values).forEach(([key, value]) => {
      if (!lockedFields.has(key)) form.setValue(key as any, value)
    })
  }, [form, lockedFields])

  const mainValue = useMemo(() => {
    if (!v || Object.keys(v).length === 0) return undefined
    const res = calcDef.compute(v)
    return typeof res.result === 'number' ? res.result : undefined
  }, [v, calcDef])

  const formContent = useMemo(() => (
    <>
      <FieldsByMode fields={calcDef.fields} useSlider={useSlider} lockedFields={lockedFields} toggleLock={toggleLock} />
    </>
  ), [calcDef, lockedFields, toggleLock, form, useSlider])

  return (
    <FormProvider {...form}>
      <PremiumCalculatorShell calculator={calculator} form={formContent} result={result} lockedFields={lockedFields} onExtraFieldsChange={setExtraFields} formula={calcDef.formula} interpretation={calcDef.interpretation} presets={presets} onPresetApply={applyPreset} onReset={() => {
  const locked = Object.fromEntries(Array.from(lockedFields).map(key => [key, form.getValues(key)]))
  form.reset()
  Object.entries(locked).forEach(([key, value]) => {
    if (value !== undefined && value !== '') form.setValue(key as any, value)
  })
}} copyResultText={copyResultText} inputs={watchedInputs} showTabs={true} useSlider={useSlider} onToggleSlider={() => setUseSlider(!useSlider)} hubCategory="conversion" mainValue={mainValue} onSaveScenario={() => Object.entries(v).filter(([, val]) => val).map(([k, val]) => `${k}: ${val}`).join('\n')} onExportCSV={() => Object.entries(v).filter(([, val]) => val).map(([k, val]) => `${k},${val}`).join('\n')} userCount={5621} />
    </FormProvider>
  )
}
